import{_ as e,o as s,c as i,a2 as a}from"./chunks/framework.DTa47_fH.js";const p=JSON.parse('{"title":"Audit Assessment","description":"","frontmatter":{},"headers":[],"relativePath":"assessment/audit.md","filePath":"assessment/audit.md"}'),o={name:"assessment/audit.md"};function n(r,t,d,c,l,u){return s(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="audit-assessment" tabindex="-1">Audit Assessment <a class="header-anchor" href="#audit-assessment" aria-label="Permalink to &quot;Audit Assessment&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Coming soon</p><p>Audit Assessment is on the roadmap. The description below reflects the planned capability.</p></div><p>Audit Assessment supports consultant-led compliance reviews where no application source code is available. A consultant records findings from interviews, document review, and on-site inspection using structured checklists. SWAO produces a deterministic compliance verdict without any LLM processing.</p><p><strong>Planned CLI:</strong> <code>swao audit init</code> / <code>swao assess --type audit</code></p><p><strong>TUI:</strong> Main Menu &gt; Run Assessment &gt; [2] Audit Assessment (coming soon)</p><hr><h2 id="what-it-will-produce" tabindex="-1">What it will produce <a class="header-anchor" href="#what-it-will-produce" aria-label="Permalink to &quot;What it will produce&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Output</th><th>What it contains</th></tr></thead><tbody><tr><td>Compliance verdict</td><td>Each framework control: SATISFIED / GAP / PARTIAL / NOT ASSESSED</td></tr><tr><td>Evidence log</td><td>Documents, interview notes, and on-site findings attributed per control</td></tr><tr><td>Auditor report</td><td>Full Markdown report suitable for regulatory submission</td></tr></tbody></table><hr><h2 id="how-it-will-work" tabindex="-1">How it will work <a class="header-anchor" href="#how-it-will-work" aria-label="Permalink to &quot;How it will work&quot;">​</a></h2><ol><li><strong>Initialise</strong> -- <code>swao audit init</code> creates the checklist structure in <code>wsp/inputs/audit/</code> based on the active compliance frameworks.</li><li><strong>Fill in checklists</strong> -- the consultant records findings directly in the YAML checklist files or via a guided TUI form.</li><li><strong>Attach evidence</strong> -- PDFs, DOCXs, and screenshots are placed in <code>wsp/inputs/audit/evidence/</code> and referenced in the checklist entries.</li><li><strong>Run</strong> -- <code>swao assess --type audit</code> reads the completed checklists and evidence, evaluates each control deterministically, and generates the output package.</li></ol><p>No LLM is required -- this is a fully offline, deterministic assessment path designed for highly regulated environments where LLM usage is restricted.</p>',12)])])}const m=e(o,[["render",n]]);export{p as __pageData,m as default};
